import{_ as e,c as i,o as n,d as a}from"./app.6ef49bbb.js";const m=JSON.parse('{"title":"Chapter 2: Types of Machine Learning","description":"","frontmatter":{},"headers":[{"level":2,"title":"2.1 Why Different Types Exist","slug":"_2-1-why-different-types-exist","link":"#_2-1-why-different-types-exist","children":[]},{"level":2,"title":"2.2 Supervised Learning (Learning with Answers)","slug":"_2-2-supervised-learning-learning-with-answers","link":"#_2-2-supervised-learning-learning-with-answers","children":[{"level":3,"title":"Key Idea","slug":"key-idea","link":"#key-idea","children":[]},{"level":3,"title":"Types of Supervised Learning","slug":"types-of-supervised-learning","link":"#types-of-supervised-learning","children":[]},{"level":3,"title":"1. Regression","slug":"_1-regression","link":"#_1-regression","children":[]},{"level":3,"title":"2. Classification","slug":"_2-classification","link":"#_2-classification","children":[]},{"level":3,"title":"When to Use Supervised Learning","slug":"when-to-use-supervised-learning","link":"#when-to-use-supervised-learning","children":[]}]},{"level":2,"title":"2.3 Unsupervised Learning (Learning Without Answers)","slug":"_2-3-unsupervised-learning-learning-without-answers","link":"#_2-3-unsupervised-learning-learning-without-answers","children":[{"level":3,"title":"Key Idea","slug":"key-idea-1","link":"#key-idea-1","children":[]},{"level":3,"title":"Main Tasks","slug":"main-tasks","link":"#main-tasks","children":[]},{"level":3,"title":"1. Clustering","slug":"_1-clustering","link":"#_1-clustering","children":[]},{"level":3,"title":"2. Dimensionality Reduction","slug":"_2-dimensionality-reduction","link":"#_2-dimensionality-reduction","children":[]},{"level":3,"title":"When to Use Unsupervised Learning","slug":"when-to-use-unsupervised-learning","link":"#when-to-use-unsupervised-learning","children":[]}]},{"level":2,"title":"2.4 Reinforcement Learning (Learning by Experience)","slug":"_2-4-reinforcement-learning-learning-by-experience","link":"#_2-4-reinforcement-learning-learning-by-experience","children":[{"level":3,"title":"Key Idea","slug":"key-idea-2","link":"#key-idea-2","children":[]},{"level":3,"title":"Key Terms","slug":"key-terms","link":"#key-terms","children":[]},{"level":3,"title":"Agent","slug":"agent","link":"#agent","children":[]},{"level":3,"title":"Environment","slug":"environment","link":"#environment","children":[]},{"level":3,"title":"Action","slug":"action","link":"#action","children":[]},{"level":3,"title":"Reward","slug":"reward","link":"#reward","children":[]},{"level":3,"title":"Example","slug":"example","link":"#example","children":[]},{"level":3,"title":"When to Use Reinforcement Learning","slug":"when-to-use-reinforcement-learning","link":"#when-to-use-reinforcement-learning","children":[]}]},{"level":2,"title":"2.5 Comparing the Three Types","slug":"_2-5-comparing-the-three-types","link":"#_2-5-comparing-the-three-types","children":[]},{"level":2,"title":"2.6 A Clear Mental Model","slug":"_2-6-a-clear-mental-model","link":"#_2-6-a-clear-mental-model","children":[]},{"level":2,"title":"2.7 Why This Matters","slug":"_2-7-why-this-matters","link":"#_2-7-why-this-matters","children":[]},{"level":2,"title":"2.8 What Comes Next","slug":"_2-8-what-comes-next","link":"#_2-8-what-comes-next","children":[]},{"level":2,"title":"Chapter Summary","slug":"chapter-summary","link":"#chapter-summary","children":[]}],"relativePath":"ml-foundation/en/part1/types-of-machine-learning.md"}'),r={name:"ml-foundation/en/part1/types-of-machine-learning.md"},t=a('<h1 id="chapter-2-types-of-machine-learning" tabindex="-1">Chapter 2: Types of Machine Learning <a class="header-anchor" href="#chapter-2-types-of-machine-learning" aria-hidden="true">#</a></h1><hr><h2 id="_2-1-why-different-types-exist" tabindex="-1">2.1 Why Different Types Exist <a class="header-anchor" href="#_2-1-why-different-types-exist" aria-hidden="true">#</a></h2><p>Machine Learning is about learning patterns from data. However, not all problems provide data in the same way.</p><p>Sometimes:</p><ul><li>We have correct answers</li><li>Sometimes we don\u2019t</li><li>Sometimes learning happens through interaction</li></ul><blockquote><p>The type of Machine Learning depends on the <strong>data and feedback available</strong>.</p></blockquote><p>There are three main types:</p><ul><li>Supervised Learning</li><li>Unsupervised Learning</li><li>Reinforcement Learning</li></ul><hr><h2 id="_2-2-supervised-learning-learning-with-answers" tabindex="-1">2.2 Supervised Learning (Learning with Answers) <a class="header-anchor" href="#_2-2-supervised-learning-learning-with-answers" aria-hidden="true">#</a></h2><h3 id="key-idea" tabindex="-1">Key Idea <a class="header-anchor" href="#key-idea" aria-hidden="true">#</a></h3><ul><li>Data has <strong>inputs + correct outputs (labels)</strong></li><li>Model learns by comparing prediction with correct answer</li></ul><blockquote><p>The model is guided during learning.</p></blockquote><p>Supervised learning is the most common type of Machine Learning. Here, the model is trained using examples where both the input and the correct output are known. By repeatedly comparing its predictions with the correct answers, the model gradually improves and learns patterns that can be applied to new data.</p><hr><h3 id="types-of-supervised-learning" tabindex="-1">Types of Supervised Learning <a class="header-anchor" href="#types-of-supervised-learning" aria-hidden="true">#</a></h3><hr><h3 id="_1-regression" tabindex="-1">1. Regression <a class="header-anchor" href="#_1-regression" aria-hidden="true">#</a></h3><ul><li><p>Output is a number</p></li><li><p>Examples:</p><ul><li>Predicting house prices</li><li>Predicting temperature</li></ul></li></ul><p>Regression means predicting a continuous value. For example:</p><ul><li>House price = \u20B945,20,000</li><li>Temperature = 32.5\xB0C</li></ul><p>The output is not fixed categories\u2014it can be any number.</p><p>Regression is used when the answer is a continuous value, such as predicting a house price or temperature. In real-world scenarios, many problems involve estimating quantities rather than choosing between categories. For instance, predicting stock prices, sales revenue, or rainfall amounts all fall under regression. The key idea is that the output can take any value within a range, and the model learns how input features influence that value.</p><hr><h3 id="_2-classification" tabindex="-1">2. Classification <a class="header-anchor" href="#_2-classification" aria-hidden="true">#</a></h3><ul><li><p>Output is a category</p></li><li><p>Examples:</p><ul><li>Spam / Not Spam</li><li>Fraud / Not Fraud</li></ul></li></ul><p>Classification means assigning data to a specific category. For example:</p><ul><li>Email \u2192 Spam</li><li>Transaction \u2192 Fraud</li></ul><p>The output is from a fixed set of categories.</p><p>Classification is used when the answer belongs to a predefined set of categories. Unlike regression, where the output is numeric, classification deals with discrete labels. For example, detecting whether an email is spam or not, identifying whether a patient has a disease, or recognizing objects in an image. The model learns boundaries between categories and uses them to classify new data points correctly.</p><hr><h3 id="when-to-use-supervised-learning" tabindex="-1">When to Use Supervised Learning <a class="header-anchor" href="#when-to-use-supervised-learning" aria-hidden="true">#</a></h3><ul><li>You have labeled data</li><li>You want to predict outcomes</li></ul><p>Supervised learning is widely used because labeled data provides clear guidance, making it easier for models to learn accurate patterns.</p><hr><h2 id="_2-3-unsupervised-learning-learning-without-answers" tabindex="-1">2.3 Unsupervised Learning (Learning Without Answers) <a class="header-anchor" href="#_2-3-unsupervised-learning-learning-without-answers" aria-hidden="true">#</a></h2><h3 id="key-idea-1" tabindex="-1">Key Idea <a class="header-anchor" href="#key-idea-1" aria-hidden="true">#</a></h3><ul><li>Data has <strong>no labels</strong></li><li>Model finds <strong>patterns on its own</strong></li></ul><blockquote><p>No guidance is given to the model.</p></blockquote><p>Unsupervised learning is used when we only have input data without any correct answers. The model explores the data and tries to identify patterns, similarities, or structures. It is often used for understanding data rather than predicting specific outputs.</p><hr><h3 id="main-tasks" tabindex="-1">Main Tasks <a class="header-anchor" href="#main-tasks" aria-hidden="true">#</a></h3><hr><h3 id="_1-clustering" tabindex="-1">1. Clustering <a class="header-anchor" href="#_1-clustering" aria-hidden="true">#</a></h3><ul><li><p>Group similar data points</p></li><li><p>Example:</p><ul><li>Grouping customers</li></ul></li></ul><p>Clustering means grouping similar items together.</p><p>Clustering is used to identify natural groupings within data. For example, a company can group customers based on purchasing behavior, allowing it to target different segments more effectively. The model does not know the groups beforehand\u2014it discovers them based on similarities in the data.</p><hr><h3 id="_2-dimensionality-reduction" tabindex="-1">2. Dimensionality Reduction <a class="header-anchor" href="#_2-dimensionality-reduction" aria-hidden="true">#</a></h3><ul><li>Reduce number of features</li><li>Simplify data</li></ul><p>Dimensionality means the number of features in data. Dimensionality reduction means reducing features while keeping important information.</p><p>Dimensionality reduction is useful when dealing with complex datasets that have many features. By reducing the number of features, we make the data easier to process and visualize while still preserving the most important information. This helps improve efficiency and sometimes even model performance.</p><hr><h3 id="when-to-use-unsupervised-learning" tabindex="-1">When to Use Unsupervised Learning <a class="header-anchor" href="#when-to-use-unsupervised-learning" aria-hidden="true">#</a></h3><ul><li>No labeled data</li><li>Need to explore patterns</li></ul><p>Unsupervised learning is often the first step in understanding unknown data.</p><hr><h2 id="_2-4-reinforcement-learning-learning-by-experience" tabindex="-1">2.4 Reinforcement Learning (Learning by Experience) <a class="header-anchor" href="#_2-4-reinforcement-learning-learning-by-experience" aria-hidden="true">#</a></h2><h3 id="key-idea-2" tabindex="-1">Key Idea <a class="header-anchor" href="#key-idea-2" aria-hidden="true">#</a></h3><ul><li>Model learns from <strong>actions + rewards</strong></li><li>No direct correct answers</li></ul><blockquote><p>Learning happens through feedback.</p></blockquote><p>Reinforcement learning is different from the other two types. Instead of learning from a fixed dataset, the model learns by interacting with an environment. It takes actions and receives feedback in the form of rewards or penalties, gradually improving its decisions over time.</p><hr><h3 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-hidden="true">#</a></h3><hr><h3 id="agent" tabindex="-1">Agent <a class="header-anchor" href="#agent" aria-hidden="true">#</a></h3><ul><li>The learner or decision-maker</li></ul><p>The agent is the system that takes actions and learns from outcomes. It is the main component responsible for making decisions.</p><hr><h3 id="environment" tabindex="-1">Environment <a class="header-anchor" href="#environment" aria-hidden="true">#</a></h3><ul><li>The world the agent interacts with</li></ul><p>The environment provides the situation in which the agent operates. It responds to the agent\u2019s actions and gives feedback.</p><hr><h3 id="action" tabindex="-1">Action <a class="header-anchor" href="#action" aria-hidden="true">#</a></h3><ul><li>A decision taken by the agent</li></ul><p>An action is any step the agent takes to interact with the environment.</p><hr><h3 id="reward" tabindex="-1">Reward <a class="header-anchor" href="#reward" aria-hidden="true">#</a></h3><ul><li>Feedback received</li></ul><p>The reward tells the agent whether its action was good or bad. The goal is to maximize rewards over time.</p><hr><h3 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-hidden="true">#</a></h3><ul><li>Game playing</li><li>Robotics</li></ul><p>In a game, the model learns which moves lead to winning. Over time, it develops strategies that improve its performance.</p><hr><h3 id="when-to-use-reinforcement-learning" tabindex="-1">When to Use Reinforcement Learning <a class="header-anchor" href="#when-to-use-reinforcement-learning" aria-hidden="true">#</a></h3><ul><li>Sequential decisions</li><li>Actions affect future outcomes</li></ul><p>Reinforcement learning is useful in dynamic environments where decisions are interconnected.</p><hr><h2 id="_2-5-comparing-the-three-types" tabindex="-1">2.5 Comparing the Three Types <a class="header-anchor" href="#_2-5-comparing-the-three-types" aria-hidden="true">#</a></h2><ul><li>Supervised \u2192 learn from answers</li><li>Unsupervised \u2192 find patterns</li><li>Reinforcement \u2192 learn from rewards</li></ul><p>Each type is suited for different kinds of problems.</p><hr><h2 id="_2-6-a-clear-mental-model" tabindex="-1">2.6 A Clear Mental Model <a class="header-anchor" href="#_2-6-a-clear-mental-model" aria-hidden="true">#</a></h2><ul><li>Supervised \u2192 Learn with a teacher</li><li>Unsupervised \u2192 Learn by observing</li><li>Reinforcement \u2192 Learn by trial and error</li></ul><hr><h2 id="_2-7-why-this-matters" tabindex="-1">2.7 Why This Matters <a class="header-anchor" href="#_2-7-why-this-matters" aria-hidden="true">#</a></h2><ul><li>Helps choose the right approach</li><li>Defines how data is used</li><li>Impacts model performance</li></ul><p>Choosing the correct type is essential for building effective systems.</p><hr><h2 id="_2-8-what-comes-next" tabindex="-1">2.8 What Comes Next <a class="header-anchor" href="#_2-8-what-comes-next" aria-hidden="true">#</a></h2><p>Next, we will explore:</p><blockquote><p>The Machine Learning Pipeline \u2014 how data moves from input to prediction.</p></blockquote><hr><h2 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-hidden="true">#</a></h2><ul><li>ML has three main types</li><li>Supervised uses labeled data</li><li>Unsupervised finds patterns</li><li>Reinforcement learns from rewards</li><li>Choosing the right type is important</li></ul><hr><p>Take time to understand each type clearly. This foundation will support everything ahead.</p><hr>',110),s=[t];function l(o,h,d,u,c,p){return n(),i("div",null,s)}const f=e(r,[["render",l]]);export{m as __pageData,f as default};
